#include <stdio.h>
#include <stdlib.h>

int abs(int x) {
    return x < 0 ? -x : x;
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N;
        scanf("%d", &N);
        int* arr = (int*)malloc(N * sizeof(int));
        for (int i = 0; i < N; i++) {
            scanf("%d", &arr[i]);
        }
        long long sum = 0;
        for (int a = 0; a < N; a++) {
            for (int b = a + 1; b < N; b++) {
                for (int c = b + 1; c < N; c++) {
                    for (int d = c + 1; d < N; d++) {
                        sum += abs(arr[a] + arr[b] - arr[c] - arr[d]);
                        sum += abs(arr[a] + arr[c] - arr[b] - arr[d]);
                        sum += abs(arr[a] + arr[d] - arr[b] - arr[c]);
                        sum += abs(arr[c] + arr[d] - arr[a] - arr[b]);
                        sum += abs(arr[b] + arr[d] - arr[a] - arr[c]);
                        sum += abs(arr[b] + arr[c] - arr[a] - arr[d]);
                    }
                }
            }
        }
        printf("%lld\n", sum);
        free(arr);
    }
    return 0;
}

