        while (T-- > 0) {
            int N = sc.nextInt();
            int[] arr = new int[N];
            for (int i = 0; i < N; i++) {
                arr[i] = sc.nextInt();
            }
            long sum = 0;
            for (int a = 0; a < N; a++) {
                for (int b = a + 1; b < N; b++) {
                    for (int c = b + 1; c < N; c++) {
                        for (int d = c + 1; d < N; d++) {
                            sum += Math.abs(arr[a] + arr[b] - arr[c] - arr[d]);
                            sum += Math.abs(arr[a] + arr[c] - arr[b] - arr[d]);
